import{_ as a,o as t,c as o,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"九大不净","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/九大不净.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/九大不净.md"}'),b={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/九大不净.md"};function i(l,e,d,c,p,_){return t(),o("div",null,[...e[0]||(e[0]=[r("h1",{id:"九大不净",tabindex:"-1"},[s("九大不净 "),r("a",{class:"header-anchor",href:"#九大不净","aria-label":'Permalink to "九大不净"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌037")])])],-1),n('<h1 id="九大不净-1" tabindex="-1">九大不净 <a class="header-anchor" href="#九大不净-1" aria-label="Permalink to &quot;九大不净&quot;">​</a></h1><p>IDEA-A-199-『九大不净』<br> 科技本质<br> A+4000<br> 分类：拳套<br> 武器伤害：基于天生武器获得11附加<br> 武器特性：【天生武器伤害由冲击转为严重】<br> 伤害类型：物理-钝击<br> 体积：1<br> 这是一对黑色的手套，质地柔软舒适，并且具有纳米纤维技术，可以在穿戴后完美贴合使用者的双手，除了通过材料学与人体力学方面的突破，将科技的结晶融会至这双手套上，令其具有在近身战中的强大基本素质之外，该武装在双手的各四个指关节处镶嵌有八颗颜色不同的异能水晶，同时在左右手手背上各镶有一颗更大的异能水晶，与其他的定制武装截然不同的是，该武装的内置异能『九大不净（Novem-Pestilentia）』是通过九种不同的和疾病相关的异能互相抵消合并后产生的异能，具有极强的传染性和不稳定性，故此，该武装内置了对应九种原异能的九位异灵（Sprite）进行管控，并且还添加了一位可以限制一切疾病的异灵来作为最终防护手段。<br> 该武装分为左右手各5枚水晶，左手与右手同时各自只能激活一枚水晶调用一种异能（即同时最多同时生效两种效果），每轮可以有一次，以自由动作使一只手上生效的异能替换为另一个异能，在这次替换之后，最多只能再以迅捷动作手动调整替换一次异能效果，并且只能与自由动作调节过异能效果的手套。<br> 也由于该武装的异灵数量是所有武装中最多的，所以，这些互相同频的异灵可以在自己控制的异能生效时，在使用者的身边具象化出自身的形象，这不会有任何实际的效果，但是，或许会对使用者的精神造成一定的损伤。<br> 以下，是左右手具有的异灵与他们能激活的异能，在需要进行豁免时，所有的负面点数都以强韧豁免，而所有产生的伴生疾病都是无支线等级的疾病。<br> 左手——————<br> 『盲鳗（Lily）』：左手食指的红色水晶，异灵的形象是一条手臂大小的，有着长满皱纹的女孩童般的人类头部，身体则是布满褶皱与粘液的无肢肉条，她的头部两侧各生长着九条蠕动挥舞的白色触须，母亲的长女，它操控黏膜发炎，带来痢疾与各类流行性感冒，以及分泌物相关疾病，该水晶激活时，攻击命中会附带不可豁免的剧痛与流血点数各1点，并且给予对方一种流行性感冒，判断来源时，视为A级疾病来源。<br> 『蠕虫（Techaridi）』：右手中指的粉色水晶，异灵的形象是一条中指大小的，浑身长满猩红细长刚毛的毛虫，口部生有两根巨大的尖牙，母亲的次女，她只攻击女性，并且以折磨亲生母亲为乐，她在血管中蠕动，并在鲜血中留下自己尖锐的刚毛，污染血液，她掌管的是血液疾病，当该水晶激活时，进行的攻击可以不造成伤害，转而造成等量的流血点数，若攻击的目标为女性，则会因出血造成产道溢血等妇科流血疾病，在判断来源时，视为A级疾病来源。<br> 『千足（Skylari）』：左手无名指上的银水晶，异灵的形象是一头手臂大小的，身体呈长条形，长有3~9根尾巴的白老鼠，这只老鼠的躯体与每条尾巴下方都长有上千条畸形细小的腿，它掌管着寒颤与发热，在该水晶激活时，进行的攻击可以不造成伤害，转而造成等量的燃烧点数，但这种燃烧点数不会直接如火焰般熊熊燃烧，而是在人体内发热、窜动，因此获得的燃烧点数的叠加，目标会在体感上愈来愈冷，实际体温则与体感的寒冷程度成反比，在判断来源时，视为A级疾病来源。<br> 特殊的，若承受了这种燃烧点数的目标喝下浸泡了干老鼠肺和老鼠胃的酒，则可以立即清除所有该异能造成的燃烧点数，但不会立即恢复已经因此损伤的生命。<br> 『蜣螂（Minsescolo）』：左手小拇指上的绿色水晶，异灵的形象是一只只有指节大小的，浑身长满漆黑硬毛的甲虫，她是母亲生下的最后一个女儿，当母亲想要为自己绝育时，听信了『双头鸟』的建议，将自己埋在粪便堆中，那之中，一只蜣螂钻入了母亲体内，又原路返回生了出来，成为了母亲的孩子，她掌管着性与生殖上的传染病，该水晶激活时，进行的攻击可以不造成伤害，转而造成等量的毒素点数，并且会给予攻击目标一种性病，如淋病、艾滋等等，在判断来源时，视为A级疾病来源。<br> 『天使（Mother）』：左手手背上的纯白水晶，异灵的形象是一位貌美慈悲的金发女孩。最终的限制手段，一切疾病（异能）的起点（母亲），该异能生效时，立即解除自身A级及以下的疾病来源的负面效果，并在该异能被替换前，免疫A级疾病来源的负面效果，相对的，当该异能正在生效时，另一只手的异能无法生效，也无法进行调整。<br> 右手——————<br> 『双头鸟（Melalo）』：右手食指的蓝色水晶，异灵的形象是一只手臂大小的，有着令人不安的两颗畸形脑袋的鸟类，恶魔的长子，它掌管精神疾病、教唆强暴、煽动愤怒与背叛等，它会像喜鹊一样喋喋不休，在使用者的耳边叽叽喳喳，令人烦躁的杂音，该水晶激活时，进行的攻击将附带等量的精神束缚点数。<br> 『刺球（Tekulo）』：右手中指的黄色水晶，异灵的形象是3cm直径、浑身长满尖刺的蠕动黄色圆球，看起来像是肿胀的海胆，父亲吃下一只楸型虫与小龙虾后行房，令母亲生下的第三子，他掌管肠道与生殖器的肿痛、胀痛、剧痛和各种类型的生理性下身疼痛，该水晶激活时，攻击附带等量的剧痛点数，这些剧痛只会分布在敌人的消化系统与生殖系统中游动，并且产生痉挛与刺痛，在判断来源时，视为A级疾病来源。<br> 『多首（Bitoso）』：右手无名指的金水晶，异灵的形象是如一只手掌般的可怖软体生物，有代替手腕与手臂部分的肉质尾巴，他是一条多头的小蠕虫，就如人的五指般生长着五条没有眼睛的触肢口器，在类似掌心的位置生长着一颗不断转动观察世界的血肉眼球，他是母亲的第六子，也是最平静和无害的孩子，他掌管着头部与生理性的恶心，也会引起牙龈疼痛和耳痛，该水晶激活时，攻击附带等量的麻痹点数。<br> 『红鼠（Lormistko）』：右手小指的橙色水晶，异灵的形象是一只没有毛皮、长满脓疮、肌肉裸露的恶心老鼠，是母亲的第五子，在生下『多首）』之后，母亲曾一度浑身长满脓疱，为了治愈这种脓疱，母亲听信了『双头鸟』的建议，将老鼠放在身上，咬破这些脓疱，这的确有效果，但有一只老鼠趁机钻入了最大的一只脓疱里，当它挤破母亲的皮肤钻出，便作为掌管皮肤疾病的『红鼠』诞生在了世上，该水晶激活时，攻击附带等量的肢体妨碍点数，并且会使得被影响的肢体长出脓疮，随着肢体妨碍点数的叠加，这种脓疮的数量和大小也会不断提高，目标的浑身也会生长出流脓的痤疮，在判断来源时，视为A级疾病来源。<br> 『孽种（Porescolo）』：右手手背的灰黑结晶，黑色与灰色不断消融，生长，互相吞噬，形成了一种混沌无序的平衡；异灵的形象是一只长着四只狗头，并从狗头和身体的间隙中挤压出四只猫头，尾巴是一条毒蛇的鸟，它雌雄同体，并且所有的嘴巴大张，从中不断自我繁殖，生育代表某种疾病的抽象杂交生物，所有的舌头都分叉，向外喷吐着恶俗晦涩的死亡寓言，这只母亲的最后一个孩子、就连生下了恶疾的恶魔都无法直视的邪恶生物，掌管着心理恐惧和癌症、白血病等世界上的一切绝症，该水晶激活时，进行的攻击将附带等量的恐惧点数，承受了这些恐惧点数的目标身体内的某一结构将会诞生出病变细胞，这些细胞可能是脊髓（白血病）也可能是不断增殖的普通细胞（癌细胞），在判断来源时，视为A级疾病来源，同时，该异能状态下进行攻击检定时，若那次攻击在不计算附加成功和任何出目变动的增益的情况下，出目大于dp总数的一半，则那次攻击最终造成的伤害将提高一倍；相对的，当该异能正在生效时，另一只手的异能无法生效，也无法进行调整。</p><p>除了每种异能各自的力量之外，每轮一次，若进行过异能的切换，则下一次攻击的加骰提升一级（至多为8加骰），特殊的，除了『天使（Mother）』与『孽种（Porescolo）』之外，其余的八种异灵之间，若左右手同时激活相同手指上的异能水晶，则会触发异能的特殊同频，名为『结合（combinare）』的异能效应，只要这种特殊的同频效应存在，加骰提升的效果就会改为常驻。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(b,[["render",i]]);export{A as __pageData,m as default};
